import{_ as a,o as s,c as l,a9 as e}from"./chunks/framework.STMWz9Nm.js";const o=JSON.parse('{"title":"模块系统与crate组织","description":"","frontmatter":{},"headers":[],"relativePath":"语言/Rust/01-Rust语言基础与核心机制/08-模块系统与crate组织.md","filePath":"语言/Rust/01-Rust语言基础与核心机制/08-模块系统与crate组织.md","lastUpdated":1777177198000}'),t={name:"语言/Rust/01-Rust语言基础与核心机制/08-模块系统与crate组织.md"};function n(h,i,p,r,d,c){return s(),l("div",null,[...i[0]||(i[0]=[e(`<h1 id="模块系统与crate组织" tabindex="-1">模块系统与crate组织 <a class="header-anchor" href="#模块系统与crate组织" aria-label="Permalink to “模块系统与crate组织”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>Rust 的模块系统，解决的是：<strong>代码如何被拆分、命名、暴露和复用</strong>。<br> crate 组织则是在更大一级回答：<strong>一个项目要由哪些库或程序单元组成</strong>。</p><p>一句话理解：</p><ul><li>module（模块）更像项目内部的分区</li><li>crate 更像一个独立编译单元 / 包装边界</li><li>Cargo 则负责把这些边界组织起来</li></ul><p>如果说前面所有权、生命周期、trait 都更偏“语言内部规则”，那模块系统和 crate 组织就是 Rust 从“会写语法”走向“能组织工程”的关键一步。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>一开始写练习代码时，所有内容都塞进 <code>main.rs</code> 似乎也能跑。<br> 但项目一旦变大，就会立刻遇到这些问题：</p><ul><li>文件越来越长</li><li>逻辑边界不清楚</li><li>哪些函数该公开、哪些不该公开不明确</li><li>不同功能之间耦合越来越重</li></ul><p>Rust 的模块系统重要就在于，它鼓励你把这些边界在代码层面表达清楚：</p><ul><li>哪些内容属于哪个模块</li><li>哪些 API 对外可见</li><li>哪些实现细节只留在内部</li><li>哪些功能适合拆成独立 crate</li></ul><p>这会直接影响代码可维护性。</p><h2 id="_3-先建立直觉" tabindex="-1">3. 先建立直觉 <a class="header-anchor" href="#_3-先建立直觉" aria-label="Permalink to “3. 先建立直觉”">​</a></h2><p>先用最朴素的方式理解：</p><ul><li><strong>module</strong>：给代码分房间</li><li><strong>pub</strong>：决定哪些门对外打开</li><li><strong>crate</strong>：整栋房子的边界</li></ul><p>比如：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> config</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>表示当前 crate 里有两个模块。<br> 而：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {}</span></span></code></pre></div><p>则表示这个函数可以被模块外使用。</p><p>所以 Rust 的模块组织不是“纯目录问题”，而是“代码可见性 + 命名空间 + 文件结构”一起工作的结果。</p><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-crate-是什么" tabindex="-1">4.1 crate 是什么 <a class="header-anchor" href="#_4-1-crate-是什么" aria-label="Permalink to “4.1 crate 是什么”">​</a></h3><p>crate 可以先粗略理解成 Rust 的一个编译单元。<br> 常见有两类：</p><ul><li>binary crate：可执行程序</li><li>library crate：可复用库</li></ul><p>例如：</p><ul><li><code>src/main.rs</code> 常对应 binary crate 入口</li><li><code>src/lib.rs</code> 常对应 library crate 入口</li></ul><p>所以学 crate 组织，第一层直觉就是：</p><ul><li>我是在写一个程序</li><li>还是在写一个可以被别人复用的库</li></ul><h3 id="_4-2-module-是什么" tabindex="-1">4.2 module 是什么 <a class="header-anchor" href="#_4-2-module-是什么" aria-label="Permalink to “4.2 module 是什么”">​</a></h3><p>module 用于把 crate 内部代码继续拆分成更清晰的结构。</p><p>例如：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> auth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> db</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> service</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>这表示当前 crate 内部按功能切成了几个模块。</p><p>它的核心价值是：</p><ul><li>减少一个文件塞满所有逻辑</li><li>建立更清晰的命名空间</li><li>让“谁该依赖谁”更容易管理</li></ul><h3 id="_4-3-pub-决定暴露边界" tabindex="-1">4.3 <code>pub</code> 决定暴露边界 <a class="header-anchor" href="#_4-3-pub-决定暴露边界" aria-label="Permalink to “4.3 pub 决定暴露边界”">​</a></h3><p>Rust 默认是偏保守的。<br> 很多东西默认对外不可见，只有显式写 <code>pub</code> 才会暴露出去。</p><p>例如：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">mod</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> math</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    pub</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, b</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> helper</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这里：</p><ul><li><code>add</code> 可以被模块外使用</li><li><code>helper</code> 只能在当前模块内部使用</li></ul><p>这套默认私有、按需公开的策略很重要，因为它会逼你思考：</p><ul><li>哪些是稳定接口</li><li>哪些只是内部实现细节</li></ul><h3 id="_4-4-路径与-use" tabindex="-1">4.4 路径与 <code>use</code> <a class="header-anchor" href="#_4-4-路径与-use" aria-label="Permalink to “4.4 路径与 use”">​</a></h3><p>Rust 里访问模块内容时，经常会看到路径和 <code>use</code>：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">use</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> crate::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">service</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">UserService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>可以理解为：</p><ul><li><code>crate</code> 表示当前 crate 根</li><li>后面沿着模块路径找到具体类型或函数</li></ul><p>而 <code>use</code> 的作用更像“把这个名字引入当前作用域，后面写起来更简洁”。</p><p>所以它本质是在处理命名空间，而不只是“语法装饰”。</p><h3 id="_4-5-文件结构与模块结构通常会对应" tabindex="-1">4.5 文件结构与模块结构通常会对应 <a class="header-anchor" href="#_4-5-文件结构与模块结构通常会对应" aria-label="Permalink to “4.5 文件结构与模块结构通常会对应”">​</a></h3><p>Rust 常见组织方式是让文件结构和模块结构保持一致。<br> 例如：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── main.rs</span></span>
<span class="line"><span>├── config.rs</span></span>
<span class="line"><span>└── service/</span></span>
<span class="line"><span>    ├── mod.rs</span></span>
<span class="line"><span>    └── user.rs</span></span></code></pre></div><p>或者较新的常见风格：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>src/</span></span>
<span class="line"><span>├── main.rs</span></span>
<span class="line"><span>├── config.rs</span></span>
<span class="line"><span>└── service/</span></span>
<span class="line"><span>    └── user.rs</span></span></code></pre></div><p>然后在代码里声明模块关系。</p><p>重点不是死记某一种目录写法，而是理解：</p><ul><li>文件结构最好服务于模块边界</li><li>模块边界最好服务于职责划分</li></ul><h3 id="_4-6-为什么不是一上来就全-pub" tabindex="-1">4.6 为什么不是一上来就全 <code>pub</code> <a class="header-anchor" href="#_4-6-为什么不是一上来就全-pub" aria-label="Permalink to “4.6 为什么不是一上来就全 pub”">​</a></h3><p>很多初学者为了省事，会把看到的一切都设成 <code>pub</code>。<br> 短期似乎顺手，但长期会带来问题：</p><ul><li>内部实现被过度暴露</li><li>API 边界变模糊</li><li>重构时牵一发而动全身</li></ul><p>更好的思路是：</p><ul><li>默认先私有</li><li>真正需要给外部调用的，再公开</li></ul><p>这和很多成熟工程里的封装原则是一致的。</p><h3 id="_4-7-crate-什么时候该拆" tabindex="-1">4.7 crate 什么时候该拆 <a class="header-anchor" href="#_4-7-crate-什么时候该拆" aria-label="Permalink to “4.7 crate 什么时候该拆”">​</a></h3><p>随着项目变大，你可能会问：</p><ul><li>这个功能继续放模块里就够了</li><li>还是应该拆成独立 crate</li></ul><p>一个朴素判断方式是看它是否已经具备这些特征：</p><ul><li>逻辑相对独立</li><li>对外接口比较清晰</li><li>未来可能被多个地方复用</li><li>希望减少主程序和它的耦合</li></ul><p>如果都成立，拆 crate 往往比在一个大文件树里继续堆模块更合理。</p><h3 id="_4-8-module-crate-组织其实是在设计依赖方向" tabindex="-1">4.8 module / crate 组织其实是在设计依赖方向 <a class="header-anchor" href="#_4-8-module-crate-组织其实是在设计依赖方向" aria-label="Permalink to “4.8 module / crate 组织其实是在设计依赖方向”">​</a></h3><p>更深一层看，模块系统不只是文件摆放问题，而是在设计：</p><ul><li>谁可以访问谁</li><li>谁依赖谁</li><li>哪些地方是上层协调</li><li>哪些地方是底层实现</li></ul><p>如果组织得好：</p><ul><li>依赖方向清晰</li><li>代码更容易替换和测试</li><li>边界更容易维护</li></ul><p>如果组织得乱：</p><ul><li>文件虽然分开了</li><li>但依赖依然一团乱麻</li></ul><p>所以“拆文件”不等于“模块设计做好了”。</p><h2 id="_5-常见误区" tabindex="-1">5. 常见误区 <a class="header-anchor" href="#_5-常见误区" aria-label="Permalink to “5. 常见误区”">​</a></h2><h3 id="_5-1-误区一-模块系统只是目录结构问题" tabindex="-1">5.1 误区一：模块系统只是目录结构问题 <a class="header-anchor" href="#_5-1-误区一-模块系统只是目录结构问题" aria-label="Permalink to “5.1 误区一：模块系统只是目录结构问题”">​</a></h3><p>不是。<br> 目录只是表象，真正重要的是：</p><ul><li>命名空间</li><li>可见性</li><li>依赖边界</li><li>职责划分</li></ul><h3 id="_5-2-误区二-能编译通过就说明组织没问题" tabindex="-1">5.2 误区二：能编译通过就说明组织没问题 <a class="header-anchor" href="#_5-2-误区二-能编译通过就说明组织没问题" aria-label="Permalink to “5.2 误区二：能编译通过就说明组织没问题”">​</a></h3><p>不一定。<br> 很多项目能跑，但模块边界已经很糟，只是问题还没大到爆出来。</p><h3 id="_5-3-误区三-pub-越多越省事" tabindex="-1">5.3 误区三：<code>pub</code> 越多越省事 <a class="header-anchor" href="#_5-3-误区三-pub-越多越省事" aria-label="Permalink to “5.3 误区三：pub 越多越省事”">​</a></h3><p>短期也许省事，长期几乎一定增加维护负担。<br> 公开接口一旦多起来，后续重构空间就会被压缩。</p><h3 id="_5-4-误区四-模块拆得越细越高级" tabindex="-1">5.4 误区四：模块拆得越细越高级 <a class="header-anchor" href="#_5-4-误区四-模块拆得越细越高级" aria-label="Permalink to “5.4 误区四：模块拆得越细越高级”">​</a></h3><p>也不是。<br> 拆太细会让跳转路径和心智成本变高。关键不在“细”，而在“边界是否自然、职责是否清楚”。</p><h2 id="_6-一个更实用的判断思路" tabindex="-1">6. 一个更实用的判断思路 <a class="header-anchor" href="#_6-一个更实用的判断思路" aria-label="Permalink to “6. 一个更实用的判断思路”">​</a></h2><p>当你准备组织 Rust 项目结构时，可以先问自己：</p><ol><li>这是一个程序 crate 还是库 crate</li><li>哪些逻辑应该归在同一个模块里</li><li>哪些内容是真正要暴露给外部的 API</li><li>这里继续做模块划分就够，还是已经值得拆成独立 crate</li><li>当前的组织方式有没有让依赖方向变得更清晰</li></ol><p>只要这几个问题想明白，模块设计通常不会太偏。</p><h2 id="_7-学习建议" tabindex="-1">7. 学习建议 <a class="header-anchor" href="#_7-学习建议" aria-label="Permalink to “7. 学习建议”">​</a></h2><p>学习模块系统与 crate 组织时，建议按这个顺序：</p><ol><li>先把单文件程序拆成两个模块</li><li>练习 <code>mod</code>、<code>pub</code>、<code>use</code> 的基本关系</li><li>再看 <code>main.rs</code> 和 <code>lib.rs</code> 的区别</li><li>再练习把一组功能整理成更清晰的目录结构</li><li>最后再接触 workspace 和多 crate 项目</li></ol><p>这样你会从“语法会写”逐步过渡到“结构会设计”。</p><h2 id="_8-自测标准" tabindex="-1">8. 自测标准 <a class="header-anchor" href="#_8-自测标准" aria-label="Permalink to “8. 自测标准”">​</a></h2><ul><li>能解释 module 和 crate 分别在解决什么问题</li><li>能区分 <code>main.rs</code> 和 <code>lib.rs</code> 的常见角色</li><li>能理解 <code>pub</code> 为什么是在定义边界</li><li>能看懂 <code>use crate::...</code> 这种路径引用</li><li>能判断什么时候该继续拆模块，什么时候值得拆成独立 crate</li></ul>`,99)])])}const u=a(t,[["render",n]]);export{o as __pageData,u as default};
